#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdint.h>

typedef struct Node {
    int key;
    int cnt;
    struct Node *next;
} Node;

#define TABLE_SIZE 262144
static Node *table[TABLE_SIZE];
static Node pool[200000];
static int pool_idx;

static unsigned int hash_int(int x) {
    return ((unsigned int)x * 2654435761u) & (TABLE_SIZE - 1);
}

static void add(int x) {
    unsigned int h = hash_int(x);
    Node *p = table[h];
    while (p) {
        if (p->key == x) { p->cnt++; return; }
        p = p->next;
    }
    Node *newnode = &pool[pool_idx++];
    newnode->key = x;
    newnode->cnt = 1;
    newnode->next = table[h];
    table[h] = newnode;
}

static int cmp_int(const void *a, const void *b) {
    int ia = *(const int*)a;
    int ib = *(const int*)b;
    return (ia > ib) - (ia < ib);
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N1, N2, N3;
        scanf("%d %d %d", &N1, &N2, &N3);
        memset(table, 0, sizeof(table));
        pool_idx = 0;
        int total = N1 + N2 + N3;
        for (int i = 0; i < total; ++i) {
            int v; scanf("%d", &v);
            add(v);
        }
        int *res = (int*)malloc(total * sizeof(int));
        int rcnt = 0;
        for (int i = 0; i < TABLE_SIZE; ++i) {
            Node *p = table[i];
            while (p) {
                if (p->cnt >= 2) res[rcnt++] = p->key;
                p = p->next;
            }
        }
        qsort(res, rcnt, sizeof(int), cmp_int);
        printf("%d\n", rcnt);
        for (int i = 0; i < rcnt; ++i) printf("%d\n", res[i]);
        free(res);
    }
    return 0;
}

