#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N1 = int(next(it)); N2 = int(next(it)); N3 = int(next(it))
        freq = {}
        for _ in range(N1):
            v = int(next(it)); freq[v] = freq.get(v, 0) + 1
        for _ in range(N2):
            v = int(next(it)); freq[v] = freq.get(v, 0) + 1
        for _ in range(N3):
            v = int(next(it)); freq[v] = freq.get(v, 0) + 1
        ans = [k for k, c in freq.items() if c >= 2]
        ans.sort()
        out_lines.append(str(len(ans)))
        out_lines.extend(str(v) for v in ans)
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

